<?php
const THIS_PAGE = 'external_feed';
require __DIR__.'/includes/config.inc.php';
require_once __DIR__.'/../custom/external_videos/lib/external_videos_lib.php';

$q = trim((string)($_GET['q'] ?? ''));
$page = max(1, (int)($_GET['page'] ?? 1));
$perPage = 48;
$total = ev_count(['published' => 1, 'q' => $q]);
$totalPages = max(1, (int)ceil($total / $perPage));
if ($page > $totalPages) { $page = $totalPages; }
$offset = ($page - 1) * $perPage;
$items = ev_list(['published' => 1, 'q' => $q, 'limit' => $perPage, 'offset' => $offset]);
$baseParams = $q !== '' ? ['q' => $q] : [];
function ev_feed_page_url(int $page, array $baseParams): string { $params = $baseParams; if ($page > 1) { $params['page'] = $page; } $query = http_build_query($params); return '/external_feed.php' . ($query ? '?' . $query : ''); }
$title = $q !== '' ? lang('oc_search_results_for', $q) : lang('oc_videos');
$desc = $q !== '' ? lang('oc_search_meta_description', $q) : lang('oc_feed_meta_description');
?><!doctype html><html lang="<?=ev_h(Language::getInstance()->getLangISO())?>"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title><?=ev_h($title)?><?= $page > 1 ? ' - '.ev_h(lang('oc_page_of', [(string)$page, (string)$totalPages])) : '' ?></title><meta name="description" content="<?=ev_h($desc)?>"><link rel="stylesheet" href="/styles/cb_28/theme/css/portal.css?v=20260629"><link rel="stylesheet" href="/styles/cb_28/theme/css/external-videos.css?v=5"></head><body class="portal-shell"><nav class="oc-portal-nav" style="position:static"><a href="/"><?=ev_h(lang('oc_home'))?></a><a href="/external_feed.php"><?=ev_h(lang('oc_videos'))?></a><a href="/videos.php"><?=ev_h(lang('oc_hosted_videos'))?></a></nav><main><section class="ev-toolbar"><div><h1 class="ev-title"><?=ev_h($title)?></h1><p class="ev-count"><?=ev_h(lang('oc_videos_found', number_format($total)))?><?= $totalPages > 1 ? ' · '.ev_h(lang('oc_page_of', [(string)$page, (string)$totalPages])) : '' ?></p></div><form class="ev-search" method="get" action="/external_feed.php"><input type="search" name="q" value="<?=ev_h($q)?>" placeholder="<?=ev_h(lang('oc_search_placeholder'))?>" aria-label="<?=ev_h(lang('oc_search_videos'))?>"><button type="submit"><?=ev_h(lang('oc_search'))?></button><?php if($q !== ''): ?><a class="ev-clear" href="/external_feed.php"><?=ev_h(lang('oc_clear'))?></a><?php endif; ?></form></section><?php if($items): ?><div class="ev-grid"><?php foreach($items as $v): ?><article class="ev-card"><a href="/external_video.php?slug=<?=rawurlencode($v['slug'])?>"><img src="<?=ev_h($v['thumbnail_url'])?>" alt="<?=ev_h($v['title'])?>" loading="lazy"><h3><?=ev_h($v['title'])?></h3><div class="ev-meta"><?=number_format((int)$v['view_count'])?> <?=ev_h(lang('oc_views'))?> · <?=ev_h($v['provider'])?> <?=((int)$v['is_18_plus']?' · 18+':'')?></div></a></article><?php endforeach;?></div><?php else: ?><div class="ev-empty"><h2><?=ev_h(lang('oc_no_videos_found'))?></h2><p><?=ev_h(lang('oc_try_different_keyword'))?></p></div><?php endif; ?><?php if($totalPages > 1): ?><nav class="ev-pagination" aria-label="<?=ev_h(lang('oc_video_pagination'))?>"><?php if($page > 1): ?><a href="<?=ev_h(ev_feed_page_url($page-1,$baseParams))?>">‹ <?=ev_h(lang('oc_previous'))?></a><?php endif; ?><?php $start=max(1,$page-2); $end=min($totalPages,$page+2); if($start>1): ?><a href="<?=ev_h(ev_feed_page_url(1,$baseParams))?>">1</a><?php if($start>2): ?><span>…</span><?php endif; endif; ?><?php for($i=$start;$i<=$end;$i++): ?><?php if($i===$page): ?><span class="active"><?=$i?></span><?php else: ?><a href="<?=ev_h(ev_feed_page_url($i,$baseParams))?>"><?=$i?></a><?php endif; ?><?php endfor; ?><?php if($end<$totalPages): ?><?php if($end<$totalPages-1): ?><span>…</span><?php endif; ?><a href="<?=ev_h(ev_feed_page_url($totalPages,$baseParams))?>"><?=$totalPages?></a><?php endif; ?><?php if($page < $totalPages): ?><a href="<?=ev_h(ev_feed_page_url($page+1,$baseParams))?>"><?=ev_h(lang('oc_next'))?> ›</a><?php endif; ?></nav><?php endif; ?></main></body></html>
